    const { M, L, C, Qk, S, 骨, 衣, 細, 逸, 陰, 陽 } = 筆;
    // ── 立骨（匠稿之節，深自其「深」）────────────────────────────────────────
    const 右上臂 = { a: 節之(-10.4, 31.1, 1), b: 節之(-13.4, 39.0, 2), ra: 2.6, rb: 2.2 };
    const 右前臂 = { a: 節之(-13.4, 39.0, 2), b: 節之(-3.1, 36.1, 6), ra: 2.0, rb: 1.55 };
    const 左上臂 = { a: 節之(13.2, 30.0, 1), b: 節之(15.2, 45.6, 2), ra: 2.5, rb: 2.0 };
    const 左前臂 = { a: 節之(15.2, 45.6, 2), b: 節之(19.4, 60.0, 4), ra: 2.0, rb: 1.55 };
